import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { FriendshipService, FriendRequest } from '../../services/friendship.service';

@Component({
  selector: 'app-friend-requests',
  standalone: true,
  imports: [CommonModule, NavbarComponent],
  templateUrl: './friend-requests.component.html',
  styleUrl: './friend-requests.component.css'
})
export class FriendRequestsComponent implements OnInit {
  requests: FriendRequest[] = [];
  loading = true;

  constructor(private friendshipService: FriendshipService) {}

  ngOnInit() {
    this.loadRequests();
  }

  loadRequests() {
    this.loading = true;
    this.friendshipService.getPendingRequests().subscribe({
      next: (requests) => {
        this.requests = requests;
        this.loading = false;
      },
      error: (err) => {
        console.error('Error loading requests:', err);
        this.loading = false;
      }
    });
  }

  acceptRequest(friendshipId: number) {
    this.friendshipService.acceptFriendRequest(friendshipId).subscribe({
      next: () => {
        this.loadRequests();
      },
      error: (err) => {
        console.error('Error accepting request:', err);
      }
    });
  }

  rejectRequest(friendshipId: number) {
    this.friendshipService.rejectFriendRequest(friendshipId).subscribe({
      next: () => {
        this.loadRequests();
      },
      error: (err) => {
        console.error('Error rejecting request:', err);
      }
    });
  }
}
<div class="friend-requests-container">
  <app-navbar></app-navbar>

  <div class="requests-content">
    <h1>Friend Requests</h1>

    <div *ngIf="loading" class="loading">Loading requests...</div>

    <div *ngIf="!loading && requests.length === 0" class="empty-state">
      <p>No pending friend requests</p>
    </div>

    <div *ngIf="!loading && requests.length > 0" class="requests-list">
      <div *ngFor="let request of requests" class="request-card">
        <div class="request-info">
          <div class="avatar">{{ request.requesterName.charAt(0).toUpperCase() }}</div>
          <h3>{{ request.requesterName }}</h3>
        </div>
        <div class="request-actions">
          <button
            class="btn btn-accept"
            (click)="acceptRequest(request.friendshipId)"
          >
            ✓ Accept
          </button>
          <button
            class="btn btn-reject"
            (click)="rejectRequest(request.friendshipId)"
          >
            ✕ Reject
          </button>
        </div>
      </div>
    </div>
  </div>
</div>
